class Writer:
    def draft(self):
        return "Title: ADK Security. We use tools to run code."

class Reviewer:
    def review(self, text):
        issues = []
        if "sandbox" not in text.lower():
            issues.append("Missing details about sandboxed execution.")
        return issues

if __name__ == '__main__':
    w = Writer()
    r = Reviewer()

    doc = w.draft()
    problems = r.review(doc)
    print("Draft:", doc)
    print("Review Issues:", problems)
